"use strict";(self.webpackChunkportfolio=self.webpackChunkportfolio||[]).push([[703],{703:e=>{e.exports=JSON.parse('{"title":"Unraveling Flight Dynamics: Investigating the Impact of Arrival Delay on Subsequent Departure Delay in Major U.S. Airports","summary":"In this project, I leveraged extensive data from the Bureau of Transportation Statistics (BTS) to analyze and optimize airport operations for major hubs, including Hartsfield-Jackson Atlanta International, Miami International, John F. Kennedy International, and Los Angeles International airports. The primary focus was on understanding the cascading effects of delayed arrivals on subsequent departures.","description":["Merged and cleaned datasets for over 30 airlines, spanning from 2000 to the present, to create comprehensive datasets for each airport. Rigorous data integrity checks were implemented to ensure accuracy.","Conducted in-depth EDA to unveil patterns and trends in arrival and departure delays. Employed various statistical and visualization techniques to identify key insights crucial for enhancing scheduling strategies.","Investigated the correlation between arrival and departure delays, revealing strong relationships that impact overall airport efficiency. Utilized statistical tools to quantify these correlations.","Explored the impact of seasonal variations on airport operations, categorizing months into busy periods. Analyzed departure and arrival delays during peak seasons, providing valuable insights for resource allocation."],"technologies_used":["Python","Pandas","Numpy","Matplotlib"],"outcome":["The project resulted in actionable insights for airport operators to proactively manage delays, improving overall efficiency and passenger satisfaction. The findings contribute to the ongoing discourse on optimizing airport operations in the face of increasing air traffic"]}')}}]);